const Q_GEOGRAPHY_1997=[{"id": "objective>Geography>1997>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Lines joining places of equal sunshine hours on a map are called?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">isobars</div>", "<div style=\"font-family:Cambria;font-size:17px;\">isotherms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">isohels</div>", "<div style=\"font-family:Cambria;font-size:17px;\">isohytes</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Isohels are lines on a map connecting points having the same or equal duration of sunshine. It shows points on a map which have the same average percentage of sunshine hours</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>1997>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most ideal statistical mapping technique for showing population migration is the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">choropleth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">flow diagram</div>", "<div style=\"font-family:Cambria;font-size:17px;\">isopleth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dot map</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The flow diagram is used to illustrate information of people leaving or entering a particular location. It illustrates information such as; transport,the relative amount of traffic,passengers or goods carried along different routes and population migration </div>", "topic": "PRATICAL GEOGRAPHY I : INTERPRETATION OF STATISTICAL DATA; MAPS AND DIAGRAMS"}, {"id": "objective>Geography>1997>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A trader in town Y on Long. 30°W telephoned his uncle in town Z on Long. 60°E at 12.00 noon. The local time the uncle received the call was?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6.00 a.m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10.00 a.m</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> 2.00 p.m</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> 6.00 p.m</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">(W) Town Y(30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>W) 12:00noon   ←Add   ? (E)Town  Z(60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>E) <br/> longitude difference = 60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> + 30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>=90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> <br/> We add since the towns are in west and east. <br/> Convert 90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> to time <br/> 360<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>≡24hours <br/> 90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> ≡90 * 24/360 <br/> 90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> ≡6hours <br/> since the arrow is pointing away from the question mark(i.e east), we add the time <br/> 12:00noon + 6hours <br/> =6:00pm <br/> Hence, the local time of the uncle is 6:00pm.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>1997>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The zone of uniform temperature in the atmosphere is known as the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">troposphere</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stratosphere</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tropopause</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ozone layer</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The troposphere is the first and lowest layer of the atmosphere of the earth. It does not contain ozone. It is a zone of uniform temperature in the atmosphere.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>1997>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Basaltic plateaux are usually formed by a lava that is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">basic and fluid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">acidic and fluid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">acidic and viscous</div>", "<div style=\"font-family:Cambria;font-size:17px;\">basic and viscous</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A basaltic plateaux is the result of a giant volcanic eruption or a series of eruptions that cover large stretches of land or ocean floor with the basalt lava.The basalt lava is basic and viscous. It is basic and viscous due to high iron and magnesium content but a low silica content </div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>1997>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Rocks, ash and sediments deposited by a volcano are collectively referred to as?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lava</div>", "<div style=\"font-family:Cambria;font-size:17px;\">detritus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pyroclasts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">scree</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A lava is a hot molten fluid erupted from a volcano. It is made up of rock, ash and sediments</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>1997>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The set of features produced in glaciated lowland includes all of?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">corries, pyramidal peak and eskers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">eskers, crag and tail and roche montanee</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pyramidal peak, erratics and moraine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">corrie roche montanee and erratics</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Eskers are long, narrow and winding ridges of sand and gravel deposited by melting water streams.Crag is a mass of hard of hard rock which slopes on the upstream side that protects the softer leeward slope from erosion and later develops to form the tail. Roche montonnee are resistant residual structure whose surface is striated by ice movement.Eskers, Crag and Tail,Roche montannee,boulder clay, Errattics,Drumlins,outwash plane and terminal moraines are all features of glaciated lowlands</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>1997>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Four ways in which a river transports its load are?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">corrosion, saltation, solution and suspension</div>", "<div style=\"font-family:Cambria;font-size:17px;\">saltation, solution, suspension and traction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">attrition, saltion, solution and suspension</div>", "<div style=\"font-family:Cambria;font-size:17px;\">corrosion, attrition, suspension and traction</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rivers transport their load in four main ways: saltation, solution, suspension, and traction. Saltation is the intermittent movement of particles over the river bed. Solution is the process where minerals in the rocks are dissolved in the water and carried along in solution. Suspension is the transportation of fine light material which is carried along in the water. Traction is the rolling along the bed of large particles and boulders. Corrosion and attrition are processes of erosion, not transportation.</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>1997>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The warm ocean current which washes the southeastern coast of Africa is called the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Benguela current</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Guinea current</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Canaries current</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Agulhas current</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Agulhas current is the warm ocean current of the southwest Indian Ocean. It flows south along the east coast of Africa from 27<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>S to 40<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>S. It is narrow,swift and strong. The sources of the Agulhas current are the east Madagascar current and the Mozambique current</div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}, {"id": "objective>Geography>1997>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following factors best explains the generally low isolation in the high latitudes?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Altitude</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Continentally</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Longitudinal position</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Angle of inclination</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When the surface warms up,the heat diffuses into and warms the atmosphere, an in turn, transfers some of the heat to the upper layers of the atmosphere.Therefore, the layers of atmosphere closest to the earth's surface(low-altitude areas) are typically warmer compared to layers of atmosphere in high-altitude areas.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>1997>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the northern winter, two well- defined low pressure cells are centered respectively on the North Atlantic Oceans because?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the sea is relatively warmer than the land</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> there are warm ocean currents</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the northern parts of the oceans are shallow</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the seas are swept by strong winds</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Due to the shallowness of the northern parts of the North Atlantic oceans, two well defined low pressure cells are centred on the ocean.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>1997>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Planetary winds are deflected on crossing the Equator due mainly to the effects of?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Coriolis force</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ferrel's law</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the jet stream</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gravitational force</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Owing to rotation of the earth, planetary winds are deflected to the right in the northern hemisphere and to the left, in the southern hemisphere.This is often referred to as the Ferrel's law of deflection</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>1997>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which savannah vegetation is characterized by grasses of about one metre high and scattered trees with flattish canopy?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sahel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sudan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Guinea</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Derived</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The majority of the grasses in the sudan savannah have a height of about one metre.They include grasses like lemon grass,Rhodes grass,star grass,Bermuda grass etc. There are also lots of trees scattered about the savannah with flattish canopy</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>1997>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The process by which materials are physically transferred from one soil layer to another is called?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">leaching</div>", "<div style=\"font-family:Cambria;font-size:17px;\">physical weathering</div>", "<div style=\"font-family:Cambria;font-size:17px;\">illuviation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">elluviation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">leaching involves the physical transfer of soil nutrients and other materials from one soil layer to another by the action of running water</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>1997>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important environmental resources that sustains natural processes in an ecosystem is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">light</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">air</div>", "<div style=\"font-family:Cambria;font-size:17px;\">energy</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Water is the most important environment resource for the existence of life. It is important for domestic uses e.g drinking, cooking etc, it is also used for industrial processess and agricultural practices like irrigation</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL RESOURCES"}, {"id": "objective>Geography>1997>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Nutrients lost by trees in leaf-fall can be re-used by the trees because the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">trees are renewable resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nutrients circulate in the ecosystem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nutrients are inexhaustible</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trees store nutrients</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">As leaves fall, they die and deay, thus returning nutrient to trees.Hence nutrients losts by trees in leaf fall can be reused through continuous circulation of nutrient in the ecosystem.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL RESOURCES"}, {"id": "objective>Geography>1997>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following human disease is often heightened by the introduction of irrigation farming in an area?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Bilharzia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dysentery</div>", "<div style=\"font-family:Cambria;font-size:17px;\">River blindness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cholera</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bilharzia is a disease caused by infection with fresh water parasitic worms in certain tropical ans subtropical areas. It is heightened by the introduction of irrigation farming in such an area</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL HAZARDS"}, {"id": "objective>Geography>1997>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One serious environmental hazard which may result from the destruction of the zone layer is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">flooding due to melting of snow</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pollution of rain water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in atmospheric temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease in the quantity of oxygen in the atmosphere</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Without the ozone layer, the earth's surface would be sterilized by ultraviolet radiation.The breakdown of the ozone layer will increase skin cancer and lead to increase in atmospheric pressure</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL INTERACTION"}, {"id": "objective>Geography>1997>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Dense population mainly dependent on peasant farming is found in?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Witwatersrand in South Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the coastal areas of West Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the Rwanda-Burundi area</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the Katanga District</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The West Africa's coastal areas host an abundance of natural resources on land and at sea that provide vital ecosystem services and are dependent on peasant farming</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>1997>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Rapid population growth is mainly the natural consequence of?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">low fertility and mortality</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rapid economic development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high fertility with high mortality</div>", "<div style=\"font-family:Cambria;font-size:17px;\">low mortality with high fertility</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mortality involves the state of being subjected to death while fertility involves the ability of being able to reproduce.A low mortality rate i.e the rate at which people are born leads to an increase in the population of a country</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>1997>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The process by which population becomes largely concentrated at certain locations is called?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">migration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">urbanization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nucleation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">agglomeration</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">urbanization refers to the growth of towns, especially in terms of human population and physical size. In other words, urbanization means a change in the functions of a settlement from a rural to an urban charactered. It develops as a result of increasing number of people coming into a certain location coupled with a proportionate increase in the physical size of that location</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>1997>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a nodal town?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Kumasi</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Port Harcourt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Banjul</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Monrovia</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A nodal town is a town which is at the centre of the social and economic function that occurs between surrounding areas. Kumasi is the capital city of the Ashanti Region, in southern Ghana. It is known as the centre for the Ashanti Culture</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>1997>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The least geographical factor that determined town sites in the past was the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">existence of fertile alluvial plains</div>", "<div style=\"font-family:Cambria;font-size:17px;\">presence of indented coastlined sheltered from waves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">existence of communication networks</div>", "<div style=\"font-family:Cambria;font-size:17px;\">presence of a river gorge</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">presence of communication networks was not really considered in the determination of town sites ages ago</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>1997>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Villages which lie along the foot of a chalk escarpment at head stream points are referred to as?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fall-line settlements</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fault-line villages</div>", "<div style=\"font-family:Cambria;font-size:17px;\">spring-line settlements</div>", "<div style=\"font-family:Cambria;font-size:17px;\">scarp-line villages</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Villages which lie along the foot of a chalk escarpment at head stream points are known as fall line settlements. The fall line represents the limit of navigation on many rivers</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>1997>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The area served by a given city is referred to as its?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sphere of influence</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hinterland</div>", "<div style=\"font-family:Cambria;font-size:17px;\">territory</div>", "<div style=\"font-family:Cambria;font-size:17px;\">satelite</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">satelites are the areas served by a given city.They are smaller cities that are near to a large city that is the centre of a metropolitan area</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>1997>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Aluminum smelters are usually located close to sources of abundant?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">raw materials</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electricity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coking coal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cheap labour</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Aluminium smelting is a continuous electrolytic process that requires significant quantities of electrical energy. Primary production involves making aluminium products from raw materials or ingots, which is highly energy intensive especially electricity intensive.So, aluminium smelters are usually located close to the source of abundant electricity</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>1997>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A country is said to have been unfavorable balance of trade when her?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tangible imports are greater in value than the tangible exports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tangible exports are greater in value than the tangible imports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">total payments for all visible and invisible imports exceed the corresponding total,exports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">total receipts from all visible and invisible exports exceed the corresponding imports</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When the total payments for all visible (goods) and invisible(services) imports exceeds the corresponding total exports(goods and service), the balance of trade of such country is unfavourable</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>1997>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An unsuitable natural condition for the cultivation of cotton is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a loose sandy soil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an annual rainfall of 500mm to 1000 mm with most of it falling in the growing season</div>", "<div style=\"font-family:Cambria;font-size:17px;\">temperature of about 21° during growing season</div>", "<div style=\"font-family:Cambria;font-size:17px;\">clear sunny skies after the plant is fully matured</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For the cultivation of cotton, rainfall has to be moderate, 500mm to 750mm is enough.Cotton plants need sufficient rainfall in the early stages of growth, but a sunny and dry weather is required after flowering</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>1997>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An agricultural practice where water has to be artificially provided during the rainy season is referred to as?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">full irrigation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">supplementary irrigation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sprinkle irrigation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">flood irrigation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">supplementary irrigation is an agricultural practice where water is artificially supplied during the raining season to supplement insufficient rainfall</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL RESOURCES"}, {"id": "objective>Geography>1997>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The leading rubber producing areas of the world are?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Malaysia, Sri Lanka and Ghana</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Liberia, Indonesia and Sierra Leone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Brazil, Malaysia and Zarie</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Malaysia, Indonesia and Sri Lanka</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The leading rubber producing areas of the world are Malaysia, Indonesia, and Sri Lanka. Malaysia and Indonesia are the top two producers of rubber in the world, with Sri Lanka also being a significant producer. Rubber trees thrive in tropical climates, which these countries have.</div>", "topic": "REGIONAL GEOGRAPHY : PLANTATION AGRICULTURE IN WEST AND EAST AFRICA"}, {"id": "objective>Geography>1997>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following countries is one of the major producers of petroleum and also a net importer of the product?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Algeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mexico</div>", "<div style=\"font-family:Cambria;font-size:17px;\">United States of America</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria  is a major producer of petroleum with a production rate of 1.6 million barrels per day but the country still spends over ₦1.506 trillion naira in the importation of crude  oil</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>1997>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The cheapest means of transport for long distance travel is by?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rail</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">air</div>", "<div style=\"font-family:Cambria;font-size:17px;\">road</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Water transport is cheaper than road,air or rail transport because it moves naturally in water and there is no requirement for investing capital in construction and maintenance of tracks as in case of railways or roads. it can carry heavy loads through a long distance at low costs</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>1997>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is an entrepot?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Rotterdam</div>", "<div style=\"font-family:Cambria;font-size:17px;\">New York</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sydney</div>", "<div style=\"font-family:Cambria;font-size:17px;\">London</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An entrepot is a port,city or trading post where merchandise may be imported, stored or traded usually to be exported again. The port of Rotterdam is a major international hub and the gateway to Europe. It is the first port of call for many shipping companies resulting in huge time savings. </div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>1997>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The global decline in the use of coal as a source of energy is due to the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> increase in nuclear and water power generation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in underground mining accidents</div>", "<div style=\"font-family:Cambria;font-size:17px;\">availability of cheaper and cleaner energy sources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decline of the iron and steel industry</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The global decline in the use of coal as a source of energy is as a result of the low cost of natural gas in generating energy as compared to coal</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>1997>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the the main reasons for the formation Economic Community of West Africa States is to?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">foster political independence among member states</div>", "<div style=\"font-family:Cambria;font-size:17px;\">encourage tourism in the area</div>", "<div style=\"font-family:Cambria;font-size:17px;\">boost manufacturing in the region</div>", "<div style=\"font-family:Cambria;font-size:17px;\">expand the market for the products of member states</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main goal of ECOWAS is to promote economic cooperation among member states in order to raise living standards and promote economic developments by expanding the  market for the products of member states </div>", "topic": "REGIONAL GEOGRAPHY : INTERNATIONAL ECONOMIC COOPERATION IN WEST AFRICA ECOWAS"}, {"id": "objective>Geography>1997>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">From which of the following lakes in Africa did the emission of toxic gas lead to the death of a large number of people in 1986?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Lake Monoum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lake Nyos</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oguta Lake</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lake Nkongsamba</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">On 21st August 1986,an emission of carbon dioxide,CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> at lake Nyos in northwestern Cameroon killed 1,746 people and 3,500 livestocks</div>", "topic": "REGIONAL GEOGRAPHY : ENVIRONMENTAL HAZARDS"}, {"id": "objective>Geography>1997>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The low level mechanized agriculture in West Africa is best explained by the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lack of markets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">seasonal variation and unreliability of rainfall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">predominance of small farm holdings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">undulating topography</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The low level of mechanized agriculture in west Africa is due to the predominance of small farm holdings.Due to law of inheritance, farms are divided and sub-divided after the death of the owners, some farms are small due to sale of parts of holdings, some farms are divided in scattered plots </div>", "topic": "REGIONAL GEOGRAPHY : PLANTATION AGRICULTURE IN WEST AND EAST AFRICA"}, {"id": "objective>Geography>1997>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Iron deposits are found in economic quantities in?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Liberia, Sierra Leone and Guinea</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mali, Nigeria and Cote d'Ivoire</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Niger, Mali and Sierra Leone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Liberia, Nigeria and Senegal</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Liberia, Sierra Leone and Guinea are area of the African continent where iron deposits are found in significantly high economic quantities</div>", "topic": "REGIONAL GEOGRAPHY : MINERAL EXPLOITATION"}, {"id": "objective>Geography>1997>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The drainage pattern illustrated in the diagram is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">annular</div>", "<div style=\"font-family:Cambria;font-size:17px;\">centripetal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">radial</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trellised</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The drainage pattern above is radial. A radial drainage pattern develops around a central elevated point where the streams radiate outwards from a central high point. The tributaries drain down in all directions</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>1997>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The type of pattern illustrated is normally associated with</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Basins</div>", "<div style=\"font-family:Cambria;font-size:17px;\">domes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">troughs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">graben</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A radial pattern develops when streams flow in different directions from a central peak or dome-like structure.The type of pattern in the diagram is associated with domes</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>1997>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The point marked with solid triangles are the locations of Nigeria's </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Thermal power stations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">International airports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Automobile assembly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oil refineries</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to the map, the points marked with solid triangles are the locations of Nigeria's oil refineries</div>", "topic": "REGIONAL GEOGRAPHY : BROAD OUTLINE OF NIGERIA"}, {"id": "objective>Geography>1997>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The shaded areas labelled Y on the map are noted for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Dry season wheat cultivation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Foodland rice cultivation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Large-scale fish farming</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Large-scale irrigation farming</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The shaded areas labelled Y on the map are areas liable to flood and eventually develop into swamps.Hence, the areas are noted for foodland rice cultivation</div>", "topic": "REGIONAL GEOGRAPHY : IRRIGATION AGRICULTURE IN THE NILE AND NIGER BASIN"}, {"id": "objective>Geography>1997>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The shaded areas labelled X on the map indicate the probable areas of the occurrence of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Phosphate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Natural gas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Marble</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lignite</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lignite often referred to as brown coal, is a sedimentary rock formed from naturally compressed heat. It is found in states such as Akwa Ibom, Anambra,Bayelsa etc.Hence, the shaded areas labelled X on the map indicate the probable areas of the occurrence of Lignite <br/> </div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>1997>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The River marked R is the River</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Gongola</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Yobe</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gurara</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Taraba</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">As shown on the map, the river marked R is a tributary of the Benue river. Hence, R  is River Gongola</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>1997>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The shaded area labelled Z on the map indicates the part of Nigeria that suffers most from</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">River blindness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tse-tse fly infestation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Drought and desertification.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Toxic waste pollution</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The area labelled Z falls in the Northwest geopolitical zone. These areas are prone to drought and desertification. Such states are Jigawa,Kaduna,Kano,Kastina,Kebbi,Sokoto and Zamfara </div>", "topic": "REGIONAL GEOGRAPHY : GEOGRAPHICAL REGIONS OF NIGERIA"}, {"id": "objective>Geography>1997>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The length of the road is approximately </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8.0km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.6km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.2km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.8km</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to the map, the length of the road is approximately 9.2km</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>1997>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The gradient along the main river between the points marked X and Y is approximately</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1:15</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:16</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:17</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:18</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">As shown on the map, the gradient along the main river between the points marked X and Y is approximately 1:18</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>1997>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The feature marked P to the north-east is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A monadnock</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A knoll</div>", "<div style=\"font-family:Cambria;font-size:17px;\">An inselberg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A volcano</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The feature marked P to the north-east is A knoll. A knoll is an isolated peak of few metres high, associated with an highland</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>1997>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The bearing of Y from X is approximately</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">155<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">160<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">165<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">170<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The bearing of Y from X in the map is approximately 160<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>1997>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the map below to answer the question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The major constraint to road development in the area is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Vegetation cover</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Drainage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Settlement pattern</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Terrain</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The drainage of the area affects the development of the road majorly.The area is poorly drained and this affects the road development majorly</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}];
